"use strict";const e=require("../utils/request.js");exports.createVenue=function(t){return e.post("/venues",t)},exports.deleteVenue=function(t){return e.del(`/venues/${t}`)},exports.getMyManagedVenues=function(){return e.get("/venues/manager/me")},exports.getVenueDetail=function(t){return e.get(`/venues/${t}`)},exports.getVenueTimeslots=function(t,u){return e.get(`/timeslots/venue/${t}/date/${u}`)},exports.updateTimeslotStatus=function(t,u){return e.patch(`/timeslots/${t}/status`,u)},exports.updateVenue=function(t,u){return e.put(`/venues/${t}`,u)},exports.updateVenueStatus=function(t,u){return e.patch(`/venues/${t}/status`,u)};
